enum {
    ERR_NONE = 0,
    ERR_OVERFLOW = 1,
    ERR_UNDERFLOW = 2,
    ERR_DIVZERO = 3
};

static __thread int my_errno = ERR_NONE;

void set_error(int code) { my_errno = ____; }
int get_error(void) { return ____; }

const char *error_str(int code) {
    switch (code) {
        case ERR_NONE:      return "no error";
        case ERR_OVERFLOW:  return "overflow";
        case ERR_UNDERFLOW: return "underflow";
        case ERR_DIVZERO:   return "division by zero";
        default:            return "unknown error";
    }
}

int safe_div(int a, int b) {
    if (b == 0) { set_error(____); return 0; }
    set_error(ERR_NONE);
    return a / b;
}

int main(void) {
    int r1 = safe_div(10, 3);
    printf("10/3=%d err=%s\n", r1, error_str(get_error()));
    int r2 = safe_div(5, 0);
    printf("5/0=%d err=%s\n", r2, error_str(get_error()));
    set_error(ERR_OVERFLOW);
    printf("manual: err=%s\n", error_str(get_error()));
    return 0;
}

